{
  "name": "CerfaFlow - Arrêté de Circulation",
  "description": "Application pour générer et gérer les demandes d'arrêtés de circulation (CERFA 14024*01) pour les entreprises de travaux."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CompanyProfile {
  companyName: string;
  siret: string;
  address: string;
  postalCode: string;
  city: string;
  contactName: string;
  phone: string;
  email: string;
}

export interface WorkRequest {
  locationAddress: string;
  locationCity: string;
  workDescription: string;
  startDate: string;
  durationDays: number;
  trafficType: 'section_courante' | 'bretelle' | 'carrefour' | 'trottoir';
  trafficRegulation: 'route_barree' | 'alternat' | 'restriction_chaussee' | 'stationnement_interdit' | 'vitesse_limitee';
  trafficDirection: 'bidirectionnel' | 'sens_unique';
  additionalInfo: string;
}

export type ViewState = 'dashboard' | 'profile' | 'request';

import { CompanyProfile } from '../types';

const PROFILE_KEY = 'cerfaflow_company_profile';

export const saveCompanyProfile = (profile: CompanyProfile): void => {
  try {
    localStorage.setItem(PROFILE_KEY, JSON.stringify(profile));
  } catch (error) {
    console.error("Failed to save profile", error);
  }
};

export const getCompanyProfile = (): CompanyProfile | null => {
  try {
    const data = localStorage.getItem(PROFILE_KEY);
    return data ? JSON.parse(data) : null;
  } catch (error) {
    console.error("Failed to load profile", error);
    return null;
  }
};

export const hasProfile = (): boolean => {
  return !!localStorage.getItem(PROFILE_KEY);
};

import { jsPDF } from "jspdf";
import { CompanyProfile, WorkRequest } from "../types";

export const generateCerfaPDF = (profile: CompanyProfile, request: WorkRequest) => {
  const doc = new jsPDF();

  // Helper for text formatting
  const lineHeight = 7;
  let y = 20;
  const margin = 15;
  const pageWidth = doc.internal.pageSize.width;
  const contentWidth = pageWidth - (margin * 2);

  // --- Header ---
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text("DEMANDE D'ARRÊTÉ DE POLICE DE LA CIRCULATION", margin, y);
  y += 8;
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("(Référence CERFA n° 14024*01)", margin, y);

  // Date of generation
  const today = new Date().toLocaleDateString('fr-FR');
  doc.text(`Fait le : ${today}`, pageWidth - margin - 40, y);

  y += 15;

  // --- Section 1: Demandeur ---
  drawSection(doc, "1. DEMANDEUR (Entreprise / Maître d'ouvrage)", y, 65);
  doc.setFontSize(10);
  doc.text(`Raison Sociale : ${profile.companyName}`, margin + 5, y + 10);
  doc.text(`SIRET : ${profile.siret}`, margin + 5, y + 17);
  doc.text(`Adresse : ${profile.address}, ${profile.postalCode} ${profile.city}`, margin + 5, y + 24);
  doc.text(`Contact : ${profile.contactName}`, margin + 5, y + 31);
  doc.text(`Téléphone : ${profile.phone}  |  Email : ${profile.email}`, margin + 5, y + 38);

  y += 70;

  // --- Section 2: Localisation ---
  drawSection(doc, "2. LOCALISATION DES TRAVAUX", y, 35);
  doc.text(`Adresse du chantier : ${request.locationAddress}`, margin + 5, y + 10);
  doc.text(`Commune : ${request.locationCity}`, margin + 5, y + 17);
  doc.text(`Emplacement : ${formatEnum(request.trafficType)}`, margin + 5, y + 24);

  y += 40;

  // --- Section 3: Nature des Travaux ---
  drawSection(doc, "3. NATURE ET CALENDRIER", y, 50);

  // Word wrap description
  const splitDesc = doc.splitTextToSize(`Description : ${request.workDescription}`, contentWidth - 10);
  doc.text(splitDesc, margin + 5, y + 10);

  // Calculate dynamic height based on description
  const descHeight = splitDesc.length * 5;
  const calendarY = y + 10 + descHeight;

  doc.text(`Date de début : ${new Date(request.startDate).toLocaleDateString('fr-FR')}`, margin + 5, calendarY);
  doc.text(`Durée estimée : ${request.durationDays} jour(s)`, margin + 80, calendarY);

  // Adjust Y for next section
  y += 30 + descHeight;

  // --- Section 4: Mesures d'exploitation ---
  drawSection(doc, "4. RÉGLEMENTATION DE LA CIRCULATION", y, 40);
  doc.text(`Mesure demandée : ${formatEnum(request.trafficRegulation)}`, margin + 5, y + 10);
  doc.text(`Sens de circulation : ${formatEnum(request.trafficDirection)}`, margin + 5, y + 17);
  if(request.additionalInfo) {
      doc.text(`Précisions : ${request.additionalInfo}`, margin + 5, y + 24);
  }

  y += 50;

  // --- Signature ---
  doc.setFont("helvetica", "italic");
  doc.text("Je soussigné, certifie l'exactitude des renseignements ci-dessus.", margin, y);
  y += 10;
  doc.setFont("helvetica", "bold");
  doc.text("Signature et Cachet :", margin + 100, y);

  // Save the PDF
  doc.save(`Demande_Arrete_${profile.companyName.replace(/\s+/g, '_')}_${today.replace(/\//g, '-')}.pdf`);
};

// Helper to draw a box with a title
const drawSection = (doc: jsPDF, title: string, y: number, height: number) => {
    const margin = 15;
    const pageWidth = doc.internal.pageSize.width;
    const width = pageWidth - (margin * 2);

    doc.setFillColor(240, 240, 240); // Light gray bg for title
    doc.rect(margin, y, width, 8, 'F');
    doc.setDrawColor(0);
    doc.rect(margin, y, width, height); // Outer border

    doc.setFont("helvetica", "bold");
    doc.setFontSize(11);
    doc.setTextColor(0);
    doc.text(title, margin + 2, y + 5.5);

    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
};

const formatEnum = (value: string) => {
    return value.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
};

import React from 'react';
import { Building2, FileText, Settings, Menu, X } from 'lucide-react';
import { ViewState } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  currentView: ViewState;
  onChangeView: (view: ViewState) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, onChangeView }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);

  const NavItem = ({ view, icon: Icon, label }: { view: ViewState; icon: any; label: string }) => {
    const isActive = currentView === view;
    return (
      <button
        onClick={() => {
          onChangeView(view);
          setIsMobileMenuOpen(false);
        }}
        className={`flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-colors duration-150 w-full ${
          isActive
            ? 'bg-brand-50 text-brand-700'
            : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
        }`}
      >
        <Icon className={`w-5 h-5 mr-3 ${isActive ? 'text-brand-600' : 'text-gray-400'}`} />
        {label}
      </button>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b px-4 py-3 flex justify-between items-center sticky top-0 z-20">
        <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold">C</div>
            <span className="font-bold text-gray-800">CerfaFlow</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X className="text-gray-600" /> : <Menu className="text-gray-600" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-10 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:translate-x-0 md:static
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col">
          <div className="h-16 flex items-center px-6 border-b">
             <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold mr-3">C</div>
             <span className="font-bold text-xl text-gray-800">CerfaFlow</span>
          </div>

          <nav className="flex-1 px-3 py-6 space-y-2">
            <NavItem view="dashboard" icon={FileText} label="Tableau de bord" />
            <NavItem view="request" icon={FileText} label="Faire une demande" />
            <NavItem view="profile" icon={Building2} label="Mon Entreprise" />
          </nav>

          <div className="p-4 border-t">
            <div className="flex items-center text-xs text-gray-400">
                <Settings className="w-4 h-4 mr-2" />
                v1.0.0
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-4xl mx-auto">
            {children}
        </div>
      </main>

      {/* Overlay for mobile menu */}
      {isMobileMenuOpen && (
        <div 
            className="fixed inset-0 bg-black bg-opacity-50 z-0 md:hidden"
            onClick={() => setIsMobileMenuOpen(false)}
        />
      )}
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { CompanyProfile } from '../types';
import { Save } from 'lucide-react';

interface CompanyFormProps {
  initialData: CompanyProfile | null;
  onSave: (data: CompanyProfile) => void;
}

const CompanyForm: React.FC<CompanyFormProps> = ({ initialData, onSave }) => {
  const [formData, setFormData] = useState<CompanyProfile>({
    companyName: '',
    siret: '',
    address: '',
    postalCode: '',
    city: '',
    contactName: '',
    phone: '',
    email: ''
  });

  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setIsSaved(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const InputField = ({ label, name, type = "text", placeholder, required = true }: any) => (
    <div className="mb-4">
      <label className="block text-sm font-medium text-gray-700 mb-1">{label}</label>
      <input
        type={type}
        name={name}
        value={(formData as any)[name]}
        onChange={handleChange}
        placeholder={placeholder}
        required={required}
        className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-brand-500"
      />
    </div>
  );

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 md:p-8">
      <div className="mb-6 border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Profil Entreprise</h2>
        <p className="text-gray-500 mt-1">Ces informations seront pré-remplies automatiquement sur vos demandes de CERFA 14024*01.</p>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6">
          <div className="md:col-span-2">
             <InputField label="Raison Sociale / Nom de l'entreprise" name="companyName" placeholder="Ex: BTP Rénovations" />
          </div>
          <InputField label="Numéro SIRET" name="siret" placeholder="14 chiffres" />
          <InputField label="Nom du contact" name="contactName" placeholder="M. Dupont Jean" />

          <div className="md:col-span-2">
            <InputField label="Adresse Postale" name="address" placeholder="123 rue de la Paix" />
          </div>

          <InputField label="Code Postal" name="postalCode" placeholder="75000" />
          <InputField label="Ville" name="city" placeholder="Paris" />

          <InputField label="Téléphone" name="phone" type="tel" placeholder="01 23 45 67 89" />
          <InputField label="Email de contact" name="email" type="email" placeholder="contact@btp-renov.com" />
        </div>

        <div className="mt-8 flex items-center justify-end">
          {isSaved && <span className="text-green-600 mr-4 text-sm font-medium animate-pulse">Informations sauvegardées !</span>}
          <button
            type="submit"
            className="flex items-center bg-brand-600 text-white px-6 py-2.5 rounded-lg hover:bg-brand-700 transition-colors shadow-sm font-medium"
          >
            <Save className="w-5 h-5 mr-2" />
            Enregistrer le profil
          </button>
        </div>
      </form>
    </div>
  );
};

export default CompanyForm;

import React, { useState, useEffect } from 'react';
import { ViewState, CompanyProfile } from './types';
import { getCompanyProfile, saveCompanyProfile } from './services/storageService';
import Layout from './components/Layout';
import CompanyForm from './components/CompanyForm';
import RequestForm from './components/RequestForm';
import { PlusCircle, Building, CheckCircle2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [profile, setProfile] = useState<CompanyProfile | null>(null);

  useEffect(() => {
    const savedProfile = getCompanyProfile();
    setProfile(savedProfile);
    if (!savedProfile && currentView !== 'profile') {
        // If no profile, we can gently nudge users or just let them see dashboard empty state
    }
  }, []);

  const handleSaveProfile = (data: CompanyProfile) => {
    saveCompanyProfile(data);
    setProfile(data);
    // Optionally redirect to request after save if they came from empty state
  };

  const renderContent = () => {
    switch (currentView) {
      case 'profile':
        return <CompanyForm initialData={profile} onSave={handleSaveProfile} />;
      case 'request':
        return <RequestForm profile={profile} onRedirectToProfile={() => setCurrentView('profile')} />;
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <header className="mb-8">
              <h1 className="text-3xl font-bold text-gray-900">Tableau de bord</h1>
              <p className="text-gray-600 mt-2">Bienvenue sur CerfaFlow, l'outil de gestion de vos arrêtés de circulation.</p>
            </header>

            {!profile ? (
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8 text-center">
                 <div className="mx-auto w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mb-4">
                    <Building className="w-8 h-8 text-blue-600" />
                 </div>
                 <h3 className="text-xl font-bold text-gray-900 mb-2">Configurez votre entreprise</h3>
                 <p className="text-gray-500 mb-6 max-w-md mx-auto">
                    Pour commencer à générer des formulaires CERFA, veuillez d'abord renseigner les informations de votre société.
                 </p>
                 <button
                    onClick={() => setCurrentView('profile')}
                    className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white bg-brand-600 hover:bg-brand-700"
                 >
                    Configurer mon profil
                 </button>
              </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Status Card */}
                    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="text-lg font-semibold text-gray-700">Votre Entreprise</h3>
                            <CheckCircle2 className="text-green-500 w-6 h-6" />
                        </div>
                        <p className="font-bold text-xl text-gray-900 mb-1">{profile.companyName}</p>
                        <p className="text-gray-500 text-sm mb-4">SIRET: {profile.siret}</p>
                        <button 
                            onClick={() => setCurrentView('profile')}
                            className="text-brand-600 text-sm font-medium hover:text-brand-800"
                        >
                            Modifier les informations →
                        </button>
                    </div>

                    {/* Action Card */}
                    <div className="bg-gradient-to-br from-brand-600 to-brand-700 rounded-xl shadow-lg p-6 text-white flex flex-col justify-between transform transition hover:scale-[1.02] cursor-pointer"
                         onClick={() => setCurrentView('request')}>
                        <div>
                            <h3 className="text-xl font-bold mb-2">Nouvelle Demande</h3>
                            <p className="text-blue-100 text-sm">Générer un formulaire CERFA 14024*01 pré-rempli pour un nouveau chantier.</p>
                        </div>
                        <div className="mt-6 flex justify-end">
                            <div className="bg-white/20 p-2 rounded-lg">
                                <PlusCircle className="w-8 h-8 text-white" />
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <div className="bg-blue-50 border border-blue-100 rounded-lg p-6 mt-8">
                <h4 className="font-semibold text-blue-900 mb-2">Comment ça marche ?</h4>
                <ol className="list-decimal list-inside space-y-2 text-sm text-blue-800">
                    <li>Renseignez une seule fois les informations de votre entreprise dans l'onglet "Mon Entreprise".</li>
                    <li>Cliquez sur "Faire une demande" pour chaque nouveau chantier.</li>
                    <li>Remplissez les détails spécifiques (dates, adresse, type de circulation).</li>
                    <li>Téléchargez instantanément le PDF officiel prêt à être envoyé à la mairie.</li>
                </ol>
            </div>
          </div>
        );
    }
  };

  return (
    <Layout currentView={currentView} onChangeView={setCurrentView}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { jsPDF } from "jspdf";
import { CompanyProfile, WorkRequest } from "../types";

export const generateCerfaPDF = (profile: CompanyProfile, request: WorkRequest) => {
  const doc = new jsPDF();
  const pageWidth = 210;
  const pageHeight = 297;

  // Colors
  const headerBgColor: [number, number, number] = [253, 233, 217]; // Light Salmon for headers

  // Fonts
  doc.setFont("helvetica", "normal");

  // --- Helper Functions ---
  const drawHeaderBox = (y: number, title: string, height: number = 7) => {
    doc.setFillColor(...headerBgColor);
    doc.setDrawColor(0);
    doc.rect(10, y, 190, height, "FD");
    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    doc.text(title, 12, y + 5);
    doc.setFont("helvetica", "normal");
    return y + height;
  };

  const drawCheckbox = (x: number, y: number, checked: boolean, label: string = "") => {
    doc.setDrawColor(0);
    doc.rect(x, y - 4, 4, 4); // Box
    if (checked) {
      doc.setFontSize(10);
      doc.text("X", x + 0.5, y - 0.5);
    }
    if (label) {
      doc.setFontSize(9);
      doc.text(label, x + 6, y - 0.5);
    }
  };

  const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 0) => {
    doc.setFontSize(9);
    doc.text(`${label} :`, x, y);
    const labelWidth = doc.getTextWidth(`${label} :`);

    doc.setFont("courier", "normal"); // Monospace for filled data looks more "form-like"
    if (maxWidth > 0) {
        // Truncate or fit
        doc.text(value, x + labelWidth + 2, y);
    } else {
        doc.text(value, x + labelWidth + 2, y);
    }
    doc.setFont("helvetica", "normal"); // Reset
  };

  // ==========================================
  // PAGE 1
  // ==========================================

  // --- Main Header ---
  // Marianne (Text simulation)
  doc.setFontSize(8);
  doc.text("Liberté • Égalité • Fraternité", 15, 15, { align: 'center' });
  doc.setFont("helvetica", "bold");
  doc.text("RÉPUBLIQUE FRANÇAISE", 15, 19, { align: 'center' });
  doc.setFont("helvetica", "normal");
  doc.text("Ministère chargé", 15, 23, { align: 'center' });
  doc.text("des transports", 15, 26, { align: 'center' });

  // Title
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text("DEMANDE D'ARRÊTÉ DE POLICE DE LA CIRCULATION", 105, 15, { align: "center" });

  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("Code de la route L411-1 à L411-7", 105, 20, { align: "center" });
  doc.text("Code général des collectivités territoriales L2213-1 à L2213-6.1", 105, 24, { align: "center" });

  doc.setFontSize(10);
  doc.setFont("helvetica", "bold");
  doc.text("Gestionnaires des réseaux routiers", 105, 30, { align: "center" });

  // Cerfa Box
  doc.rect(170, 10, 30, 15);
  doc.setFontSize(12);
  doc.text("cerfa", 185, 17, { align: "center" });
  doc.setFontSize(9);
  doc.text("N° 14024*01", 185, 22, { align: "center" });

  let y = 35;

  // --- 1. LE DEMANDEUR ---
  y = drawHeaderBox(y, "Le demandeur");

  // Checkboxes in header
  drawCheckbox(50, y - 2, false, "Particulier");
  drawCheckbox(80, y - 2, false, "Service public");
  drawCheckbox(110, y - 2, false, "Maître d'œuvre");
  drawCheckbox(170, y - 2, true, "Entreprise");

  doc.rect(10, y, 190, 45); // Section border
  y += 6;

  drawField("Nom", profile.companyName, 12, y);
  drawField("Prénom", profile.contactName.split(' ')[1] || '', 110, y); // Try to split name
  y += 7;
  drawField("Dénomination", profile.companyName, 12, y);
  drawField("Représenté par", profile.contactName, 110, y);
  y += 7;
  drawField("Adresse", profile.address, 12, y);
  y += 7;
  drawField("Code postal", profile.postalCode, 12, y);
  drawField("Localité", profile.city, 60, y);
  drawField("Pays", "France", 140, y);
  y += 7;
  drawField("Téléphone", profile.phone, 12, y);
  y += 7;
  drawField("Courriel", profile.email, 12, y);

  y += 12; // Gap

  // --- 2. LOCALISATION ---
  let startY = y;
  y = drawHeaderBox(y, "Localisation du site concerné par la demande");
  doc.rect(10, y, 190, 35); // Section border
  y += 6;

  // Determine road type from input or just show text
  let isAgglo = true; // Default to agglomeration based on most inputs
  drawField("Voie concernée", request.trafficType === 'section_courante' ? "Section courante" : request.trafficType, 12, y);

  // Checkboxes for agglo
  drawCheckbox(110, y + 6, !isAgglo, "Hors agglomération");
  drawCheckbox(150, y + 6, isAgglo, "En agglomération");
  y += 12;

  drawField("Adresse / PR", request.locationAddress, 12, y);
  y += 7;
  drawField("Code postal", "", 12, y); // Assuming unknown specific CP for site, or use company? Let's leave blank or use city logic
  drawField("Localité", request.locationCity, 60, y);

  y += 18; // Gap

  // --- 3. NATURE ET DATE ---
  y = drawHeaderBox(y, "Nature et date des travaux");
  doc.rect(10, y, 190, 45); 
  y += 6;

  drawCheckbox(60, y - 1, false, "Oui");
  drawCheckbox(75, y - 1, true, "Non");
  doc.setFontSize(9);
  doc.text("Permission de voirie antérieure :", 12, y);

  y += 7;
  doc.text("Description des travaux :", 12, y);
  y += 4;
  doc.setFont("courier", "normal");
  const splitDesc = doc.splitTextToSize(request.workDescription, 180);
  doc.text(splitDesc, 15, y);
  doc.setFont("helvetica", "normal");

  y = startY + 50 + 45 - 10; // Bottom of section 3
  drawField("Date prévue de début", new Date(request.startDate).toLocaleDateString('fr-FR'), 12, y);
  drawField("Durée (jours calendaires)", request.durationDays.toString(), 110, y);

  y += 15; // Gap

  // --- 4. REGLEMENTATION SOUHAITEE ---
  y = drawHeaderBox(y, "Réglementation souhaitée");
  doc.rect(10, y, 190, 65);
  y += 6;

  drawField("Durée de la réglementation", request.durationDays.toString(), 12, y);
  drawField("Début", new Date(request.startDate).toLocaleDateString('fr-FR'), 110, y);
  y += 7;

  // Row 1 checkboxes
  drawCheckbox(12, y, request.trafficType === 'section_courante', "Restriction sur section courante");
  drawCheckbox(110, y, request.trafficType === 'bretelle', "Restriction sur bretelles");
  y += 7;

  // Sens de circulation
  doc.text("Sens de circulation :", 12, y);
  drawCheckbox(50, y, request.trafficDirection === 'bidirectionnel', "Deux sens de circulation");
  drawCheckbox(140, y, request.trafficDirection === 'sens_unique', "Sens unique / Alternat");
  y += 7;
  drawCheckbox(140, y, request.trafficRegulation === 'route_barree', "Fermeture à la circulation");
  y += 7;

  // Alternat
  doc.text("Circulation alternée :", 12, y);
  drawCheckbox(50, y, request.trafficRegulation === 'alternat', "Par feux / Piquets");
  drawCheckbox(100, y, false, "Manuellement");
  y += 7;

  // Restriction chaussée
  doc.text("Restriction de chaussée :", 12, y);
  y += 5;
  drawCheckbox(15, y, false, "Neutralisation BAU");
  drawCheckbox(80, y, request.trafficRegulation === 'restriction_chaussee', "Empiètement sur chaussée");
  drawCheckbox(15, y + 7, false, "Suppression de voie");

  // ==========================================
  // PAGE 2
  // ==========================================
  doc.addPage();
  y = 20;

  // --- Interdiction de ... ---
  doc.rect(10, y, 190, 40);
  doc.setFont("helvetica", "bold");
  doc.text("Interdiction de :", 12, y + 5);
  doc.setFont("helvetica", "normal");
  y += 10;

  // Columns: Circuler, Stationner, Dépasser
  doc.text("Circuler", 40, y);
  doc.text("Stationner", 90, y);
  doc.text("Dépasser", 140, y);
  y += 5;

  const isStationnement = request.trafficRegulation === 'stationnement_interdit';
  const isRouteBarree = request.trafficRegulation === 'route_barree';

  drawCheckbox(45, y, isRouteBarree); // Circuler
  drawCheckbox(95, y, isStationnement); // Stationner
  drawCheckbox(145, y, false); // Depasser

  doc.text("Tous véhicules", 12, y);
  y += 10;

  // Vitesse
  const isVitesse = request.trafficRegulation === 'vitesse_limitee';
  drawField("Vitesse limitée à", isVitesse ? "30" : "", 12, y);
  doc.text("km/h", 55, y);

  y += 10;
  drawField("Autres prescriptions", request.additionalInfo, 12, y);

  y += 20;

  // --- Signalisation ---
  y = drawHeaderBox(y, "La pose, le maintien ou le retrait de la signalisation sont effectués par :");
  doc.rect(10, y, 190, 40);
  y += 6;

  drawCheckbox(12, y, true, "Le demandeur");
  drawCheckbox(60, y, false, "Une entreprise spécialisée");
  y += 6;

  // Fill company info again for Signage responsibility
  drawField("Nom / Dénomination", profile.companyName, 12, y);
  y += 6;
  drawField("Adresse", profile.address + ", " + profile.city, 12, y);
  y += 6;
  drawField("Téléphone", profile.phone, 12, y);

  y += 25;

  // --- Pièces Jointes ---
  y = drawHeaderBox(y, "Pièces jointes à la demande");
  doc.rect(10, y, 190, 25);
  y += 6;

  drawCheckbox(12, y, true, "Plan de situation");
  drawCheckbox(12, y + 6, true, "Plan des travaux");
  drawCheckbox(12, y + 12, true, "Schéma de signalisation");

  y += 30;

  // --- Signature ---
  doc.rect(10, y, 190, 30);
  y += 6;

  drawCheckbox(12, y, true, "J'atteste de l'exactitude des informations fournies");
  y += 8;

  const today = new Date().toLocaleDateString('fr-FR');
  drawField("Fait à", profile.city, 12, y);
  drawField("Le", today, 100, y);

  y += 8;
  drawField("Nom", profile.companyName, 12, y);
  drawField("Qualité", "Gérant / Responsable", 100, y);

  y += 8;
  doc.setFont("helvetica", "bold");
  doc.text("Signature et Cachet", 140, y + 5);

  // Save
  doc.save(`CERFA_14024-01_${profile.companyName.replace(/\s+/g, '_')}_${today.replace(/\//g, '-')}.pdf`);
};

import React, { useState, useEffect } from 'react';
import { CompanyProfile } from '../types';
import { Save } from 'lucide-react';

interface CompanyFormProps {
  initialData: CompanyProfile | null;
  onSave: (data: CompanyProfile) => void;
}

interface InputFieldProps {
  label: string;
  name: keyof CompanyProfile;
  value: string;
  onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  type?: string;
  placeholder?: string;
  required?: boolean;
}

// Composant extrait pour éviter la perte de focus lors du re-rendu du parent
const InputField: React.FC<InputFieldProps> = ({ label, name, value, onChange, type = "text", placeholder, required = true }) => (
  <div className="mb-4">
    <label className="block text-sm font-medium text-gray-700 mb-1">{label}</label>
    <input
      type={type}
      name={name}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      required={required}
      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-brand-500"
    />
  </div>
);

const CompanyForm: React.FC<CompanyFormProps> = ({ initialData, onSave }) => {
  const [formData, setFormData] = useState<CompanyProfile>({
    companyName: '',
    siret: '',
    address: '',
    postalCode: '',
    city: '',
    contactName: '',
    phone: '',
    email: ''
  });

  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setIsSaved(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 md:p-8">
      <div className="mb-6 border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Profil Entreprise</h2>
        <p className="text-gray-500 mt-1">Ces informations seront pré-remplies automatiquement sur vos demandes de CERFA 14024*01.</p>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6">
          <div className="md:col-span-2">
             <InputField 
                label="Raison Sociale / Nom de l'entreprise" 
                name="companyName" 
                value={formData.companyName}
                onChange={handleChange}
                placeholder="Ex: BTP Rénovations" 
             />
          </div>
          <InputField 
            label="Numéro SIRET" 
            name="siret" 
            value={formData.siret}
            onChange={handleChange}
            placeholder="14 chiffres" 
          />
          <InputField 
            label="Nom du contact" 
            name="contactName" 
            value={formData.contactName}
            onChange={handleChange}
            placeholder="M. Dupont Jean" 
          />

          <div className="md:col-span-2">
            <InputField 
                label="Adresse Postale" 
                name="address" 
                value={formData.address}
                onChange={handleChange}
                placeholder="123 rue de la Paix" 
            />
          </div>

          <InputField 
            label="Code Postal" 
            name="postalCode" 
            value={formData.postalCode}
            onChange={handleChange}
            placeholder="75000" 
          />
          <InputField 
            label="Ville" 
            name="city" 
            value={formData.city}
            onChange={handleChange}
            placeholder="Paris" 
          />

          <InputField 
            label="Téléphone" 
            name="phone" 
            type="tel" 
            value={formData.phone}
            onChange={handleChange}
            placeholder="01 23 45 67 89" 
          />
          <InputField 
            label="Email de contact" 
            name="email" 
            type="email" 
            value={formData.email}
            onChange={handleChange}
            placeholder="contact@btp-renov.com" 
          />
        </div>

        <div className="mt-8 flex items-center justify-end">
          {isSaved && <span className="text-green-600 mr-4 text-sm font-medium animate-pulse">Informations sauvegardées !</span>}
          <button
            type="submit"
            className="flex items-center bg-brand-600 text-white px-6 py-2.5 rounded-lg hover:bg-brand-700 transition-colors shadow-sm font-medium"
          >
            <Save className="w-5 h-5 mr-2" />
            Enregistrer le profil
          </button>
        </div>
      </form>
    </div>
  );
};

export default CompanyForm;

/**
 * IMPORTANT: 
 * Pour que l'application génère le PDF officiel parfait, vous devez :
 * 1. Prendre votre fichier PDF "cerfa_14024-01.pdf" officiel.
 * 2. Le convertir en Base64 (via un site comme "pdf to base64").
 * 3. Coller la longue chaîne de caractères résultante ci-dessous à la place de la chaîne vide.
 */

// Ceci est une version PDF vide "placeholder" minimale pour que l'app fonctionne immédiatement.
// Remplacez-la par votre vrai PDF converti en Base64.
export const CERFA_TEMPLATE_BASE64 = "";

import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';
import { CompanyProfile, WorkRequest } from "../types";
import { CERFA_TEMPLATE_BASE64 } from './cerfaTemplate';

export const generateCerfaPDF = async (profile: CompanyProfile, request: WorkRequest) => {
  try {
    // 1. Load the existing PDF
    const pdfDoc = await PDFDocument.load(CERFA_TEMPLATE_BASE64);
    const helveticaFont = await pdfDoc.embedFont(StandardFonts.Helvetica);
    const pages = pdfDoc.getPages();
    const firstPage = pages[0];

    // Helper to draw text
    const draw = (text: string, x: number, y: number, size: number = 10) => {
      if (!text) return;
      firstPage.drawText(text, {
        x,
        y,
        size,
        font: helveticaFont,
        color: rgb(0, 0, 0),
      });
    };

    // Helper to draw 'X' in checkboxes
    // Coordinates are Lower-Left based (PDF standard)
    const check = (x: number, y: number, isChecked: boolean) => {
      if (isChecked) {
        firstPage.drawText('X', {
          x: x,
          y: y,
          size: 12,
          font: helveticaFont,
          color: rgb(0, 0, 0),
        });
      }
    };

    /**
     * COORDONNÉES MAPPÉES SUR LE CERFA 14024*01 OFFICIEL
     * Basé sur une page A4 standard (595 x 842 points)
     * Origine (0,0) en bas à gauche.
     */

    // --- SECTION 1: DEMANDEUR ---
    // Checkbox "Entreprise" (Top right section header)
    check(556, 738, true); 

    // Dénomination (Nom de l'entreprise)
    draw(profile.companyName, 90, 712);

    // Représenté par (Contact)
    draw(profile.contactName, 350, 712);

    // Adresse (Numéro + Rue)
    // Le formulaire a "Numéro", "Extension", "Nom de la voie". On simplifie en mettant tout dans "Nom de la voie" si nécessaire ou on concatène
    draw(profile.address, 160, 702);

    // Code Postal (On met juste le texte, espacer les caractères serait idéal mais complexe)
    draw(profile.postalCode, 85, 692);

    // Localité
    draw(profile.city, 160, 692);

    // Téléphone
    draw(profile.phone, 85, 682);

    // Courriel
    draw(profile.email, 60, 672);

    // --- SECTION 2: LOCALISATION ---

    // Voie concernée (On coche "Voie communale" par défaut si non spécifié, ou on écrit le type)
    // Ici on écrit le texte dans l'espace vide si possible ou on coche. 
    // Simplification : on écrit le type et le nom de la voie dans "Nom de la voie"
    draw(`${request.trafficType === 'section_courante' ? '' : request.trafficType} ${request.locationAddress}`, 160, 558);

    // En agglomération (Checkbox) - x: ~320 y: ~568
    check(323, 568, true); 

    // Commune
    draw(request.locationCity, 160, 543);


    // --- SECTION 3: NATURE ET TRAVAUX ---

    // Permission voirie antérieure "Non" (par défaut)
    check(165, 465, true);

    // Description des travaux (multiline)
    // On coupe le texte manuellement car drawText ne fait pas le retour à la ligne auto sans conf
    const description = request.workDescription;
    draw(description.substring(0, 90), 20, 445);
    draw(description.substring(90, 180), 20, 435); // Ligne 2 si besoin

    // Date début
    // Format JJ MM AAAA (cases) -> on écrit JJ/MM/AAAA juste au dessus
    draw(new Date(request.startDate).toLocaleDateString('fr-FR'), 160, 395);

    // Durée
    draw(request.durationDays.toString(), 490, 395);


    // --- SECTION 4: REGLEMENTATION ---

    // Durée réglementation (souvent identique durée travaux)
    draw(request.durationDays.toString(), 230, 355);
    // Date début réglementation
    draw(new Date(request.startDate).toLocaleDateString('fr-FR'), 400, 355);

    // Checkboxes types
    if (request.trafficType === 'section_courante') check(165, 335, true); // Restriction section courante
    if (request.trafficType === 'bretelle') check(275, 335, true); // Restriction bretelle

    // Sens
    if (request.trafficDirection === 'bidirectionnel') check(355, 320, true); // Deux sens
    // Si alternat
    if (request.trafficRegulation === 'alternat') {
        check(205, 290, true); // Par feux tricolores (supposition standard)
        // Ou check(265, 290, true); // Manuellement
    }

    // Restriction
    if (request.trafficRegulation === 'restriction_chaussee') {
        check(375, 275, true); // Empiètement sur chaussée
    }

    // --- PAGE 2 ---
    // Si le PDF a 2 pages
    if (pages.length > 1) {
        const secondPage = pages[1];

        const checkP2 = (x: number, y: number, isChecked: boolean) => {
            if (isChecked) {
                secondPage.drawText('X', { x, y, size: 12, font: helveticaFont });
            }
        };
        const drawP2 = (text: string, x: number, y: number) => {
            secondPage.drawText(text, { x, y, size: 10, font: helveticaFont });
        };

        // Interdiction de stationner
        if (request.trafficRegulation === 'stationnement_interdit') {
             checkP2(275, 765, true); // Colonne Stationner / VL
        }

        // Route barrée (Interdiction de circuler)
        if (request.trafficRegulation === 'route_barree') {
             checkP2(165, 765, true); // Colonne Circuler / VL
        }

        // Vitesse
        if (request.trafficRegulation === 'vitesse_limitee') {
            drawP2("30", 110, 720);
        }

        // Signature section (Bas de page 2)
        // Le demandeur (checkbox)
        checkP2(110, 565, true);

        // Info signature
        drawP2(profile.companyName, 30, 545); // Nom
        drawP2(profile.contactName, 350, 545); // Prénom
        drawP2(profile.companyName, 100, 530); // Dénomination

        drawP2(profile.city, 60, 240); // Fait à
        drawP2(new Date().toLocaleDateString('fr-FR'), 150, 240); // Le
        drawP2("Gérant", 360, 225); // Qualité
    }

    // Serialize and save
    const pdfBytes = await pdfDoc.save();

    // Trigger download
    const blob = new Blob([pdfBytes], { type: 'application/pdf' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `CERFA_14024-01_${profile.companyName.replace(/\s+/g, '_')}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

  } catch (error) {
    console.error("Error generating PDF:", error);
    alert("Erreur lors de la génération du PDF. Vérifiez que le template Base64 est correct.");
  }
};

import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';
import { CompanyProfile, WorkRequest } from "../types";
import { CERFA_TEMPLATE_BASE64 } from './cerfaTemplate';

export const generateCerfaPDF = async (profile: CompanyProfile, request: WorkRequest) => {
  try {
    // 1. Load the existing PDF
    const pdfDoc = await PDFDocument.load(CERFA_TEMPLATE_BASE64);
    const helveticaFont = await pdfDoc.embedFont(StandardFonts.Helvetica);
    const pages = pdfDoc.getPages();
    const firstPage = pages[0];

    // Helper to draw text
    const draw = (text: string, x: number, y: number, size: number = 9) => {
      if (!text) return;
      firstPage.drawText(text, {
        x,
        y,
        size,
        font: helveticaFont,
        color: rgb(0, 0, 0),
      });
    };

    // Helper to draw 'X' in checkboxes
    const check = (x: number, y: number, isChecked: boolean) => {
      if (isChecked) {
        firstPage.drawText('X', {
          x: x,
          y: y,
          size: 14,
          font: helveticaFont,
          color: rgb(0, 0, 0),
        });
      }
    };

    /**
     * COORDONNÉES MAPPÉES SUR LE CERFA 14024*01 OFFICIEL
     * Basé sur une page A4 standard (595 x 842 points)
     * Origine (0,0) en bas à gauche.
     */

    // --- SECTION 1: LE DEMANDEUR ---
    // Checkbox "Entreprise" (Dans le bandeau "Le demandeur")
    check(556, 742, true); 

    // Ligne 1: Nom / Prénom (Laissés vides si c'est une entreprise, ou on met le contact)
    // On met le nom de la société dans "Dénomination" ligne 2, c'est plus propre pour une entreprise.

    // Ligne 2: Dénomination / Représenté par
    draw(profile.companyName, 120, 708, 10);
    draw(profile.contactName, 380, 708, 10);

    // Ligne 3: Adresse (Numéro / Extension / Nom de la voie)
    // On met toute l'adresse dans "Nom de la voie" pour simplifier car souvent l'adresse est un bloc
    draw(profile.address, 160, 693);

    // Ligne 4: Code postal / Localité / Pays
    draw(profile.postalCode, 85, 678);
    draw(profile.city, 180, 678);
    draw("France", 450, 678);

    // Ligne 5: Téléphone
    draw(profile.phone, 85, 663);

    // Ligne 6: Courriel
    draw(profile.email, 60, 648);


    // --- SECTION 2: LOCALISATION DU SITE ---

    // Ligne 1: Voie concernée (Autoroute / RN / RD / VC)
    // On écrit le type et le nom de la voie du chantier
    let roadType = "";
    if (request.trafficType === 'section_courante') roadType = "VC / Rue";
    else if (request.trafficType === 'bretelle') roadType = "Bretelle";
    else roadType = request.trafficType;

    // On essaye de placer ça dans "Voie communale" (fin de ligne) par défaut ou "Route départementale"
    draw(roadType + " " + request.locationAddress, 450, 567);

    // Checkboxes Agglomération (Ligne juste en dessous de voie concernée)
    // Hors agglo (x: 323), En agglo (x: 455)
    check(455, 563, true); // Par défaut en agglo

    // Ligne 3: Adresse chantier (Numéro / Extension / Nom de la voie)
    draw(request.locationAddress, 160, 537);

    // Ligne 4: Code postal / Localité
    // On réutilise le CP de l'entreprise si on n'a pas celui du chantier, ou on laisse vide.
    // draw(profile.postalCode, 85, 508); 
    draw(request.locationCity, 180, 508);


    // --- SECTION 3: NATURE ET DATE DES TRAVAUX ---

    // Ligne 1: Permission de voirie antérieure (Non par défaut)
    check(212, 463, true); // Case "Non"

    // Ligne 2 & 3: Description
    const description = request.workDescription;
    // Découpage simple si trop long
    if (description.length > 95) {
        draw(description.substring(0, 95), 25, 448);
        draw(description.substring(95, 190), 25, 436);
    } else {
        draw(description, 25, 448);
    }

    // Bas de section: Date début / Durée
    // Date prévue de début des travaux
    draw(new Date(request.startDate).toLocaleDateString('fr-FR'), 170, 385);
    // Durée
    draw(request.durationDays.toString(), 480, 385);


    // --- SECTION 4: REGLEMENTATION SOUHAITEE ---

    // Ligne 1: Durée / Date début
    draw(request.durationDays.toString(), 220, 355);
    draw(new Date(request.startDate).toLocaleDateString('fr-FR'), 430, 355);

    // Ligne 2: Restriction sur section courante / bretelles
    if (request.trafficType === 'section_courante') check(163, 340, true);
    if (request.trafficType === 'bretelle') check(275, 340, true);

    // Ligne 3: Sens de circulation
    // Deux sens
    if (request.trafficDirection === 'bidirectionnel') check(250, 325, true); 

    // Ligne 3 (droite): Fermeture à la circulation
    if (request.trafficRegulation === 'route_barree') check(556, 317, true);

    // Ligne 4: Alternat
    if (request.trafficRegulation === 'alternat') {
        check(202, 296, true); // Par feux tricolores (gauche)
        // check(330, 296, true); // Manuellement (droite)
    }

    // Ligne 5: Restriction de chaussée
    if (request.trafficRegulation === 'restriction_chaussee') {
        check(418, 281, true); // Empiètement sur chaussée
    }


    // --- PAGE 2 ---
    if (pages.length > 1) {
        const secondPage = pages[1];

        const checkP2 = (x: number, y: number, isChecked: boolean) => {
            if (isChecked) {
                secondPage.drawText('X', { x, y, size: 14, font: helveticaFont });
            }
        };
        const drawP2 = (text: string, x: number, y: number) => {
            secondPage.drawText(text, { x, y, size: 9, font: helveticaFont });
        };

        // Tableau Interdictions
        // Colonnes: Circuler (X~100), Stationner (X~250), Dépasser (X~400)
        // Ligne VL (Véhicules Légers) ~ Y=760

        if (request.trafficRegulation === 'route_barree') {
             checkP2(110, 762, true); // Interdiction de circuler
        }
        if (request.trafficRegulation === 'stationnement_interdit') {
             checkP2(260, 762, true); // Interdiction de stationner
        }

        // Vitesse limitée
        if (request.trafficRegulation === 'vitesse_limitee') {
            drawP2("30", 100, 715);
        }

        // Autres prescriptions (commentaires)
        if (request.additionalInfo) {
            drawP2(request.additionalInfo, 25, 680);
        }

        // Section Signalisation (effectuée par)
        // Checkbox "Le demandeur"
        checkP2(110, 583, true); 

        // Coordonnées entreprise dans section signalisation
        drawP2(profile.companyName, 60, 563); // Nom
        drawP2(profile.contactName, 380, 563); // Représenté par
        drawP2(profile.address, 160, 548); // Adresse
        drawP2(profile.postalCode, 85, 533); // CP
        drawP2(profile.city, 180, 533); // Ville
        drawP2(profile.phone, 85, 518); // Tel

        // Bas de page: Signature
        // "J'atteste..."
        checkP2(212, 275, true);

        // Fait à / Le
        drawP2(profile.city, 60, 245);
        drawP2(new Date().toLocaleDateString('fr-FR'), 160, 245);

        // Signataire
        drawP2(profile.companyName, 60, 230); // Nom
        drawP2("Gérant", 450, 230); // Qualité
    }

    // Serialize and save
    const pdfBytes = await pdfDoc.save();

    // Trigger download
    const blob = new Blob([pdfBytes], { type: 'application/pdf' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `CERFA_14024-01_${profile.companyName.replace(/\s+/g, '_')}_${request.locationCity}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

  } catch (error) {
    console.error("Error generating PDF:", error);
    alert("Erreur lors de la génération du PDF. Vérifiez que le template Base64 est correct.");
  }
};

import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';
import { CompanyProfile, WorkRequest } from "../types";
import { CERFA_TEMPLATE_BASE64 } from './cerfaTemplate';

export const generateCerfaPDF = async (profile: CompanyProfile, request: WorkRequest) => {
