        if (request.trafficRegulation === 'route_barree') {
             checkP2(110, 762, true); // Interdiction de circuler
        }
        if (request.trafficRegulation === 'stationnement_interdit') {
             checkP2(260, 762, true); // Interdiction de stationner
        }

