        checkP2(110, 583, true); 

        // Coordonnées entreprise dans section signalisation
        drawP2(profile.companyName, 60, 563); // Nom
        drawP2(profile.contactName, 380, 563); // Représenté par
        drawP2(profile.address, 160, 548); // Adresse
        drawP2(profile.postalCode, 85, 533); // CP
        drawP2(profile.city, 180, 533); // Ville
        drawP2(profile.phone, 85, 518); // Tel

        // Bas de page: Signature
        // "J'atteste..."
        checkP2(212, 275, true);

        // Fait à / Le
        drawP2(profile.city, 60, 245);
        drawP2(new Date().toLocaleDateString('fr-FR'), 160, 245);

        // Signataire
        drawP2(profile.companyName, 60, 230); // Nom
        drawP2("Gérant", 450, 230); // Qualité
    }

    // Serialize and save
    const pdfBytes = await pdfDoc.save();

    // Trigger download
    const blob = new Blob([pdfBytes], { type: 'application/pdf' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `CERFA_14024-01_${profile.companyName.replace(/\s+/g, '_')}_${request.locationCity}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

  } catch (error) {
    console.error("Error generating PDF:", error);
    alert("Erreur lors de la génération du PDF. Vérifiez que le template Base64 est correct.");
  }
};

